mapper.insert:
MERGE INTO TB_BOX_IVT_ENPR_INFO_M TBIEIM

USING DUAL ON (TBIEIM.UTLINSTT_ID = #{utlinsttId})

WHEN MATCHED THEN
    UPDATE SET
        TBIEIM.ETNM          = #{bplcNm}
        , TBIEIM.INCR_YMD    = #{fondDe}
        , TBIEIM.AMNN_TS     = CURRENT_TIMESTAMP

        , TBIEIM.CMPNY_LOGO_IMAGE_FILE      = #{cmpnyLogoImageFile}
        , TBIEIM.CMPNY_LOGO_BASS_IMAGE_FILE = #{cmpnyLogoBassImageFile}
        , TBIEIM.POST_NO                    = #{postNo}
        , TBIEIM.ADRES                      = #{adres}
        , TBIEIM.DETAIL_ADRES               = #{detailAdres}
        , TBIEIM.NW_ADRES                   = #{nwAdres}
        , TBIEIM.NW_ADRES_DETAIL            = #{nwAdresDetail}
        , TBIEIM.NW_ADRES_AT                = #{nwAdresAt}

        , TBIEIM.BZN                        = #{bizrno}
        , TBIEIM.ACVT_YN                    = #{actAt}
        , TBIEIM.ENPR_JNNG_DT               = #{enprJnngDt}


WHEN NOT MATCHED THEN
    INSERT
    (
        TBIEIM.UTLINSTT_ID
        , TBIEIM.ETNM
        , TBIEIM.INCR_YMD
        , TBIEIM.RGSN_TS
        , TBIEIM.AMNN_TS

        , TBIEIM.CMPNY_LOGO_IMAGE_FILE
        , TBIEIM.CMPNY_LOGO_BASS_IMAGE_FILE
        , TBIEIM.POST_NO
        , TBIEIM.ADRES
        , TBIEIM.DETAIL_ADRES
        , TBIEIM.NW_ADRES
        , TBIEIM.NW_ADRES_DETAIL
        , TBIEIM.NW_ADRES_AT

        , TBIEIM.BZN
        , TBIEIM.ACVT_YN
        , TBIEIM.ENPR_JNNG_DT
    )
    VALUES
    (
        #{utlinsttId}
        , #{bplcNm}
        , #{fondDe}
        , CURRENT_TIMESTAMP
        , CURRENT_TIMESTAMP

        , #{cmpnyLogoImageFile}
        , #{cmpnyLogoBassImageFile}
        , #{postNo}
        , #{adres}
        , #{detailAdres}
        , #{nwAdres}
        , #{nwAdresDetail}
        , #{nwAdresAt}

        , #{bizrno}
        , #{actAt}
        , #{enprJnngDt}
    )

INSERT INTO TB_BOX_IVT_EXNT_PGSG_R
(
    INVM_EXNT_RQST_ID
    , INVM_EXNT_PGSG_CD
    , RGSN_USER_ID
    , RGSN_TS
)
VALUES
(
    #{invmExntRqstId}
    , #{invmExntPgsgCd}
    , #{rgsnUserId}
    , CURRENT_TIMESTAMP
)

MERGE INTO TB_BOX_IVT_IR_B_BSIN_M tbiibbm

USING DUAL ON (tbiibbm.UTLINSTT_ID = #{utlinsttId})

WHEN MATCHED THEN
    UPDATE SET
        tbiibbm.BNNM         = #{bnnm}
        , tbiibbm.BZN          = #{bzn}
        , tbiibbm.COL          = #{col}
        , tbiibbm.RPRNM        = #{rprnm}
        , tbiibbm.BTNM         = #{btnm}
        , tbiibbm.CGN          = #{cgn}
        , tbiibbm.ADR          = #{adr}
        , tbiibbm.ZPCD         = #{zpcd}
        , tbiibbm.AMNN_USER_ID = #{amnnUserId}
        , tbiibbm.AMNN_TS      = CURRENT_TIMESTAMP

WHEN NOT MATCHED THEN
    INSERT
    (
        tbiibbm.UTLINSTT_ID
        , tbiibbm.BNNM
        , tbiibbm.BZN
        , tbiibbm.COL
        , tbiibbm.RPRNM
        , tbiibbm.BTNM
        , tbiibbm.CGN
        , tbiibbm.ADR
        , tbiibbm.ZPCD
        , tbiibbm.RGSN_USER_ID
        , tbiibbm.RGSN_TS
        , tbiibbm.AMNN_USER_ID
        , tbiibbm.AMNN_TS
    )
    VALUES
    (
        #{utlinsttId}
        , #{bnnm}
        , #{bzn}
        , #{col}
        , #{rprnm}
        , #{btnm}
        , #{cgn}
        , #{adr}
        , #{zpcd}
        , #{rgsnUserId}
        , CURRENT_TIMESTAMP
        , #{amnnUserId}
        , CURRENT_TIMESTAMP
    )

